update orders
set status = #{order.status},
cancel_reason = #{order.cancelReason},
cancel_time = #{order.cancelTime}
where id = #{order.id}

mapper.select:
select * from orders


        and number like concat('%',#{number},'%')


        and phone like concat('%',#{phone},'%')


        and user_id = #{userId}


        and status = #{status}


        and order_time >= #{beginTime}


        and order_time <= #{endTime}


order by order_time desc

select DATE(order_time) as date, COUNT(*) as value from orders where order_time >= #{begin} and order_time < #{end} and status in
#{status}
group by DATE(order_time) order by date
